// src/app/layout.tsx
import type { Metadata } from "next";
import { Roboto } from "next/font/google";
import "./globals.css";
import Sidebar from "../components/Sidebar"; // Mantemos o caminho relativo seguro

// Configuração da fonte Roboto
const roboto = Roboto({ 
  weight: ['300', '400', '500', '700'],
  subsets: ['latin'],
  variable: '--font-roboto',
});

export const metadata: Metadata = {
  title: "Atelier V2 | Portal do Cliente",
  description: "Acompanhe a criação da sua identidade visual de forma imersiva.",
};

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <html lang="pt-BR" className={`${roboto.variable}`}>
      {/* O BODY agora representa o "Lado de Fora" do aplicativo.
        Usamos um tom muito claro e neutro (um cinza/creme bem lavado) para que a Janela principal salte aos olhos.
        O 'h-screen' e 'flex items-center justify-center' centralizam a nossa aplicação no meio da tela do monitor.
      */}
      <body className="font-sans antialiased bg-[#f2eee9] text-atelier-grafite h-screen flex items-center justify-center p-4 lg:p-8 selection:bg-atelier-terracota selection:text-atelier-creme overflow-hidden">
        
        {/* A JANELA DO APLICATIVO (App Window)
          Esta é a grande sacada da imagem de referência. Uma caixa com cantos super arredondados,
          sombra difusa elegante e uma borda branca sutil para dar o efeito de vidro/soft UI.
        */}
        <div className="flex w-full max-w-[1700px] h-full max-h-[950px] bg-[#fbf4e4] rounded-[3rem] shadow-[0_20px_80px_rgba(122,116,112,0.12)] border-[6px] border-white/60 overflow-hidden relative backdrop-blur-sm">

          {/* A Sidebar será injetada aqui dentro, perfeitamente alinhada à esquerda */}
          <Sidebar />

          {/* Área do Conteúdo (Onde as páginas carregam).
            A rolagem acontece APENAS aqui dentro (overflow-y-auto), a Janela e a Sidebar ficam imóveis.
            A classe 'scrollbar-hide' (que configuraremos depois) esconderá a barra de rolagem feia do Windows/Mac.
          */}
          <main className="flex-1 overflow-y-auto p-8 lg:p-10 pl-32 relative z-10">
            {children}
          </main>

        </div>

      </body>
    </html>
  );
}